(self.webpackChunkvuepress_blog=self.webpackChunkvuepress_blog||[]).push([[7306],{2937:(n,s,a)=>{"use strict";a.r(s),a.d(s,{data:()=>e});const e={key:"v-63de5bc1",path:"/pages/html/usefulTips/",title:"",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:3,title:"rel属性详解",slug:"rel属性详解",children:[]},{level:3,title:"dns-prefetch、preconnect、Preload、prefetch",slug:"dns-prefetch、preconnect、preload、prefetch",children:[]},{level:3,title:"crossorigin",slug:"crossorigin",children:[]},{level:3,title:"integrity",slug:"integrity",children:[]},{level:3,title:"上传预览图片",slug:"上传预览图片",children:[]},{level:3,title:"标签页通信-BroadcastChannel",slug:"标签页通信-broadcastchannel",children:[]}],filePathRelative:"pages/html/usefulTips/README.md",git:{updatedTime:1709695554e3,contributors:[{name:"COOKIES-LGL",email:"1344714332@qq.com",commits:6}]}}},4801:(n,s,a)=>{"use strict";a.r(s),a.d(s,{default:()=>t});const e=(0,a(6252).uE)('<h3 id="rel属性详解"><a class="header-anchor" href="#rel属性详解">#</a> rel属性详解</h3><h4 id="rel-alternate"><a class="header-anchor" href="#rel-alternate">#</a> rel=&quot;alternate&quot;</h4><ul><li>alternate 是交替、替换，标识链接有替换内容</li></ul><div class="language-HTML ext-HTML line-numbers-mode"><pre class="language-HTML"><code>&lt;!-- 可以用来告知 SEO、屏幕阅读器有 H5 端 --&gt;\n&lt;link rel=&quot;alternate&quot; media=&quot;only screen and (max-width: 640px)&quot; href=&quot;https://m.xxx.com/&quot; /&gt;\n&lt;!-- rel=&quot;alternate&quot; 定义网站的替换样式 --&gt;\n&lt;link href=&quot;default.css&quot; rel=&quot;stylesheet&quot; type=&quot;text/css&quot; title=&quot;默认&quot;&gt;\n&lt;link href=&quot;red.css&quot; rel=&quot;alternate stylesheet&quot; type=&quot;text/css&quot; title=&quot;红色&quot;&gt;\n&lt;link href=&quot;green.css&quot; rel=&quot;alternate stylesheet&quot; type=&quot;text/css&quot; title=&quot;绿色&quot;&gt;\n&lt;!-- 上述 3 个 css 文件均会加载，但 red.css 和 green.css 的优先级为 Lowest, 即在空闲时加载，不会影响页面性能\n使用时，切换 disabled 即可，例如要启用红色的皮肤样式，其他的设置 disabled 为 true，红色的设置 disabled 为 false（注意 disabled 为 DOM 属性，link 标签上没有这个属性） --&gt;\n&lt;script&gt;\ndocument.querySelector(&#39;link[href=&quot;red.css&quot;]&#39;).disabled = false;\n&lt;/script&gt;\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><h4 id="rel-canonica"><a class="header-anchor" href="#rel-canonica">#</a> rel=&quot;canonica&quot;</h4><div class="language-HTML ext-HTML line-numbers-mode"><pre class="language-HTML"><code>&lt;link rel=&quot;canonical&quot; href=&quot;https://edu.51cto.com&quot; /&gt;\n指定规范网页，用在 link 中; 告知搜索引擎，以哪个地址为规范版本，降低其他地址的抓取频率\n比如你的站点可以通过多个域名访问、或者既有移动端又有 PC 端，这时候就能设定你想要的地址为搜索引擎优化抓取\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h4 id="rel-nofollow"><a class="header-anchor" href="#rel-nofollow">#</a> rel=&quot;nofollow&quot;</h4><p>禁止搜索引擎追踪，一般不重要的链接设置，防止搜索引擎爬取从而降低主要内容的权重 比如首页，应该只保留列表页，详情页，友链的链接追踪；对于如logo回到首页，一些不重要的链接进入登录后的页面等，均需要设置 nofollow</p><h4 id="dns-优化"><a class="header-anchor" href="#dns-优化">#</a> DNS 优化</h4><p>rel=&quot;dns-prefetch&quot; DNS 预读取 rel=&quot;preconnect&quot; DNS 预链接 rel=&quot;preload&quot; 强制浏览器提前加载资源 优先级为 high rel=&quot;prefetch&quot; 资源预拉取 优先级为 low rel=&quot;prerender&quot; 预渲染</p><div class="language-HTML ext-HTML line-numbers-mode"><pre class="language-HTML"><code>&lt;meta http-equiv=&quot;x-dns-prefetch-control&quot; content=&quot;on&quot;&gt; \n&lt;link rel=&quot;preconnect&quot; href=&quot;https://xxx.com/&quot;&gt; \n&lt;link rel=&quot;dns-prefetch&quot; href=&quot;https://xxx.com/&quot;&gt; \n&lt;link rel=&quot;preload&quot; href=&quot;https://xxx.com/&quot;&gt; \n&lt;link rel=&quot;prefetch&quot; href=&quot;https://xxx.com/&quot;&gt; \n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="dns-prefetch、preconnect、preload、prefetch"><a class="header-anchor" href="#dns-prefetch、preconnect、preload、prefetch">#</a> dns-prefetch、preconnect、Preload、prefetch</h3><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>由于dns-prefetch 仅执行 DNS查找，不像preconnect 会建立与服务器的连接.如果页面需要建立与许多第三方域的连接，则将它们预先连接会适得其反。 preconnect 提示最好仅用于最关键的连接。对于其他的，只需使用 <link rel="dns-prefetch"> 即可节省第一步的时间DNS查找</p><p>Preload 与 prefetch 不同的地方就是它专注于当前的页面，并以高优先级加载资源，Prefetch 专注于下一个页面将要加载的资源并以低优先级加载。同时也要注意 preload 并不会阻塞 window 的 onload 事件。</p></div><h4 id="防盗链"><a class="header-anchor" href="#防盗链">#</a> 防盗链</h4><p>rel=&quot;noreferrer&quot; rel=&quot;noopener&quot;</p><h3 id="crossorigin"><a class="header-anchor" href="#crossorigin">#</a> crossorigin</h3><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span> <span class="token attr-name">src</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>user.com/index.js<span class="token punctuation">&quot;</span></span> <span class="token attr-name">crossorigin</span> <span class="token punctuation">&gt;</span></span><span class="token script"></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>\n- 加载了具有crossorigin属性的跨域js脚本，这样就可以获取到user.com/index.js中的具体错误信息了。\n- crossorigin会让浏览器启用CORS访问检查，检查http响应头的Access-Control-Allow-Origin\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="integrity"><a class="header-anchor" href="#integrity">#</a> integrity</h3><p><code>integrity</code>的作用有：避免由【托管在CDN的资源被篡改】而引入的XSS 风险</p><h3 id="上传预览图片"><a class="header-anchor" href="#上传预览图片">#</a> 上传预览图片</h3><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token comment">// window.URL.createObjectURL</span>\n<span class="token keyword">function</span> <span class="token function">imgChange</span><span class="token punctuation">(</span><span class="token parameter">img</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n document<span class="token punctuation">.</span><span class="token function">querySelector</span><span class="token punctuation">(</span><span class="token string">&quot;img&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span>src<span class="token operator">=</span>window<span class="token punctuation">.</span><span class="token constant">URL</span><span class="token punctuation">.</span><span class="token function">createObjectURL</span><span class="token punctuation">(</span>img<span class="token punctuation">.</span>files<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n\n<span class="token comment">// FileReader</span>\n<span class="token keyword">function</span> <span class="token function">imgChange</span><span class="token punctuation">(</span><span class="token parameter">img</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token comment">// 生成一个文件读取的对象</span>\n    <span class="token keyword">const</span> reader <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">FileReader</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n    reader<span class="token punctuation">.</span><span class="token function-variable function">onload</span> <span class="token operator">=</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token parameter">ev</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n        document<span class="token punctuation">.</span><span class="token function">querySelector</span><span class="token punctuation">(</span><span class="token string">&quot;img&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span>src <span class="token operator">=</span> imgFile<span class="token punctuation">;</span>\n    <span class="token punctuation">}</span>\n    <span class="token comment">//发起异步读取文件请求，读取结果为data:url的字符串形式，</span>\n    reader<span class="token punctuation">.</span><span class="token function">readAsDataURL</span><span class="token punctuation">(</span>img<span class="token punctuation">.</span>files<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><h3 id="标签页通信-broadcastchannel"><a class="header-anchor" href="#标签页通信-broadcastchannel">#</a> 标签页通信-BroadcastChannel</h3><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>BroadcastChannel 只能在相同的源（origin）下工作, 不需要使用 BroadcastChannel 实例时，通过 close() 方法手动关闭频道，以便释放资源</p></div><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>\n<span class="token keyword">const</span> channel <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">BroadcastChannel</span><span class="token punctuation">(</span><span class="token string">&#39;myChannel&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n\nchannel<span class="token punctuation">.</span><span class="token function">addEventListener</span><span class="token punctuation">(</span><span class="token string">&#39;message&#39;</span><span class="token punctuation">,</span> <span class="token parameter">event</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;Received message:&#39;</span><span class="token punctuation">,</span> event<span class="token punctuation">.</span>data<span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n\nchannel<span class="token punctuation">.</span><span class="token function">postMessage</span><span class="token punctuation">(</span><span class="token string">&#39;Hello, other windows!&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div>',24),t={render:function(n,s){return e}}}}]);